_BANNER_B64 = (
    ""
)

def resource(name):
    base = getattr(sys,"_MEIPASS", os.path.dirname(os.path.abspath(__file__)))
    return os.path.join(base, name)

def load_banner(master):
    import base64 as _b64_bnr, io as _io_bnr
    try:
        from PIL import Image as PILImage, ImageTk
        raw = _b64_bnr.b64decode(_BANNER_B64)
        img = PILImage.open(_io_bnr.BytesIO(raw))
        bw, bh = img.size
        target_w = 560
        target_h = max(80, min(int(bh * target_w / bw), 120))
        img = img.resize((target_w, target_h), PILImage.LANCZOS)
        photo = ImageTk.PhotoImage(img)
        lbl = tk.Label(master, image=photo, bg=BG2, bd=0)
        lbl.image = photo
        lbl.pack(fill="x")
        return
    except Exception: pass
    # Fallback se PIL indisponível
    f = tk.Frame(master, bg=BG2, height=110)
    f.pack(fill="x"); f.pack_propagate(False)
    tk.Label(f, text="BSP", font=("Segoe UI", 30, "bold"),
             bg=BG2, fg=CYAN).place(relx=0.5, rely=0.28, anchor="center")
    tk.Label(f, text=APP_FULL, font=("Segoe UI", 9),
             bg=BG2, fg=TEXT).place(relx=0.5, rely=0.60, anchor="center")
    tk.Label(f, text=f"v{APP_VERSION}  \u00b7  {PUBLISHER}",
             font=("Segoe UI", 8), bg=BG2, fg=DIM
             ).place(relx=0.5, rely=0.82, anchor="center")


def create_shortcut(target, shortcut_path, icon=None, description=""):
    vbs = (
        'Set oWS = WScript.CreateObject("WScript.Shell")\n'
        f'Set oLink = oWS.CreateShortcut("{shortcut_path}")\n'
        f'oLink.TargetPath = "{target}"\n'
        f'oLink.WorkingDirectory = "{os.path.dirname(target)}"\n'
        f'oLink.Description = "{description}"\n'
        + (f'oLink.IconLocation = "{icon}"\n' if icon else "")
        + "oLink.Save\n"
    )
    tmp = os.environ.get("TEMP","C:/Temp") + "\\bsp_lnk.vbs"
    with open(tmp,"w") as f: f.write(vbs)
    subprocess.run(["cscript","//nologo",tmp], capture_output=True)
    try: os.remove(tmp)
    except: pass

def register_uninstall(install_dir, exe_path, icon_path, uninst_path):
    if not WINDOWS: return
    kp = f"Software\\Microsoft\\Windows\\CurrentVersion\\Uninstall\\{APP_NAME}"
    try:
        k = winreg.CreateKey(winreg.HKEY_CURRENT_USER, kp)
        for name, typ, val in [
            ("DisplayName",     winreg.REG_SZ,   APP_FULL),
            ("DisplayVersion",  winreg.REG_SZ,   APP_VERSION),
            ("Publisher",       winreg.REG_SZ,   PUBLISHER),
            ("InstallLocation", winreg.REG_SZ,   str(install_dir)),
            ("DisplayIcon",     winreg.REG_SZ,   icon_path),
            ("UninstallString", winreg.REG_SZ,   f'"{uninst_path}"'),
            ("EstimatedSize",   winreg.REG_DWORD, 150000),
            ("NoModify",        winreg.REG_DWORD, 1),
            ("NoRepair",        winreg.REG_DWORD, 1),
        ]: winreg.SetValueEx(k, name, 0, typ, val)
        winreg.CloseKey(k)
    except Exception as e: print(f"Registry: {e}")


class InstallerApp(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title(f"BSP  v{APP_VERSION}  -  {T('inst_btn_inst').strip()}")
        self.geometry("560x510"); self.resizable(False,False)
        self.configure(bg=BG)
        self.install_dir   = tk.StringVar(value=str(INSTALL_DIR))
        self.opt_desktop   = tk.BooleanVar(value=True)
        self.opt_startmenu = tk.BooleanVar(value=True)
        self.opt_launch    = tk.BooleanVar(value=True)
        self._center(); self._set_icon(); self._build()

    def _center(self):
        self.update_idletasks()
        x=(self.winfo_screenwidth()-560)//2; y=(self.winfo_screenheight()-510)//2
        self.geometry(f"560x510+{x}+{y}")

    def _set_icon(self):
        ico = resource(ICON_NAME)
        if os.path.exists(ico):
            try: self.iconbitmap(ico)
            except: pass

    def _build(self):
        for w in self.winfo_children(): w.destroy()
        load_banner(self)
        tk.Frame(self, bg=CYAN, height=2).pack(fill="x")

        # Language bar
        lang_bar = tk.Frame(self, bg=BG3, height=28); lang_bar.pack(fill="x"); lang_bar.pack_propagate(False)
        tk.Label(lang_bar, text=T('lbl_idioma') + ':', font=("Segoe UI",8), bg=BG3, fg=DIM
                 ).pack(side='left', padx=(10,4), fill='y')
        _lang_flags = {'PT':'🇵🇹','EN':'🇬🇧','ES':'🇪🇸','DE':'🇩🇪'}
        for cod in list(LINGUAS_DISPONIVEIS.keys())[:4]:
            _active = (cod == lingua_atual())
            tk.Button(lang_bar, text=f"{_lang_flags.get(cod,'')} {cod}",
                      bg=CYAN if _active else BG3,
                      fg="#0d1117" if _active else DIM,
                      relief='flat', font=("Segoe UI",8,"bold" if _active else "normal"),
                      cursor='hand2', padx=6, pady=2,
                      command=lambda c=cod: [definir_lingua(c), self._build()]
                      ).pack(side='left', fill='y', padx=1)

        sub = tk.Frame(self, bg=BG2, height=28); sub.pack(fill="x"); sub.pack_propagate(False)
        tk.Label(sub, text=APP_FULL, font=("Segoe UI",9), bg=BG2, fg=DIM
                 ).place(x=20, rely=0.5, anchor="w")
        tk.Label(sub, text=f"v{APP_VERSION}", font=("Segoe UI",9), bg=BG2, fg=DIM
                 ).place(x=540, rely=0.5, anchor="e")

        body = tk.Frame(self, bg=BG, padx=28, pady=12); body.pack(fill="both", expand=True)

        tk.Label(body, text=T('inst_pasta'), font=("Segoe UI",9), bg=BG, fg=DIM).pack(anchor="w")
        df = tk.Frame(body, bg=BG); df.pack(fill="x", pady=(4,10))
        self._entry = tk.Entry(df, textvariable=self.install_dir, bg=BG3, fg=TEXT,
                               insertbackground=TEXT, relief="flat", font=("Segoe UI",9),
                               highlightthickness=1, highlightbackground=ACCENT)
        self._entry.pack(side="left", fill="x", expand=True, ipady=7, ipadx=6)
        tk.Button(df, text="...", bg=BG3, fg=DIM, relief="flat", font=("Segoe UI",9),
                  cursor="hand2", command=self._browse, padx=12).pack(side="left", padx=(4,0))

        tk.Label(body, text=T('inst_opcoes'), font=("Segoe UI",9), bg=BG, fg=DIM).pack(anchor="w", pady=(2,4))
        _lang = lingua_atual()
        for var, lbl_pt, lbl_en, lbl_es, lbl_de in [
            (self.opt_desktop,   "  Criar atalho no Desktop", "  Create Desktop shortcut", "  Crear acceso directo", "  Desktop-Verknüpfung erstellen"),
            (self.opt_startmenu, "  Adicionar ao menu Iniciar", "  Add to Start menu", "  Añadir al menú Inicio", "  Zum Startmenü hinzufügen"),
            (self.opt_launch,    f"  Abrir {APP_NAME} após instalação", f"  Open {APP_NAME} after install", f"  Abrir {APP_NAME} tras instalación", f"  {APP_NAME} nach Installation öffnen"),
        ]:
            lbl_map = {'PT':lbl_pt,'EN':lbl_en,'ES':lbl_es,'DE':lbl_de}
            lbl = lbl_map.get(_lang, lbl_en)
            tk.Checkbutton(body, text=lbl, variable=var, bg=BG, fg=TEXT, selectcolor=BG3,
                           activebackground=BG, activeforeground=TEXT,
                           font=("Segoe UI",9), relief="flat", cursor="hand2").pack(anchor="w", pady=1)

        self.prog_frame = tk.Frame(body, bg=BG)
        self.prog_bar   = ttk.Progressbar(self.prog_frame, mode="determinate", length=500)
        self.prog_lbl   = tk.Label(self.prog_frame, text="", bg=BG, fg=DIM, font=("Segoe UI",8))
        sty = ttk.Style(); sty.theme_use("default")
        sty.configure("TProgressbar", troughcolor=BG3, background=CYAN,
                      bordercolor=BG3, lightcolor=CYAN, darkcolor=CYAN)

        footer = tk.Frame(self, bg=BG2, height=54); footer.pack(fill="x", side="bottom")
        footer.pack_propagate(False)
        tk.Label(footer, text=PUBLISHER, font=("Segoe UI",8), bg=BG2, fg=DIM
                 ).place(x=20, rely=0.5, anchor="w")
        self.btn_cancel = tk.Button(footer, text=T('inst_btn_cancel'), bg=BG2, fg=DIM, relief="flat",
                                    font=("Segoe UI",9), cursor="hand2", command=self.destroy,
                                    padx=18, pady=6)
        self.btn_cancel.place(x=540, rely=0.5, anchor="e")
        self.btn_install = tk.Button(footer, text=T('inst_btn_inst'), bg=ACCENT, fg=WHITE,
                                     relief="flat", font=("Segoe UI",10,"bold"), cursor="hand2",
                                     command=self._start, padx=22, pady=7)
        self.btn_install.place(x=454, rely=0.5, anchor="e")

    def _browse(self):
        from tkinter import filedialog
        d = filedialog.askdirectory(initialdir=self.install_dir.get())
        if d: self.install_dir.set(os.path.join(d, APP_NAME))

    def _start(self):
        self.btn_install.config(state="disabled", text=T('inst_btn_instalar'))
        self.btn_cancel.config(state="disabled")
        self.prog_frame.pack(fill="x", pady=(10,0))
        self.prog_bar.pack(fill="x"); self.prog_lbl.pack(anchor="w", pady=(2,0))
        threading.Thread(target=self._install, daemon=True).start()

    def _prog(self, v, msg=""):
        self.prog_bar["value"] = v; self.prog_lbl.config(text=msg); self.update_idletasks()

    def _install(self):
        try:
            d = Path(self.install_dir.get())
            self._prog(5, "..."); d.mkdir(parents=True, exist_ok=True)
            self._prog(18, f"{APP_NAME}...")
            shutil.copy2(resource(EXE_NAME), d/EXE_NAME)
            self._prog(35, "...")
            ico = resource(ICON_NAME)
            if os.path.exists(ico): shutil.copy2(ico, d/ICON_NAME)
            self._prog(50, "...")
            uninst_src = resource(UNINST_NAME)
            uninst_dst = d/UNINST_NAME
            if os.path.exists(uninst_src):
                shutil.copy2(uninst_src, uninst_dst); uninst_path = str(uninst_dst)
            else:
                bat = d/"BSP_Uninstall.bat"
                bat.write_text(
                    "@echo off\n"
                    f'rd /s /q "{d}" >nul 2>&1\n'
                    f'reg delete "HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\Uninstall\\{APP_NAME}" /f >nul 2>&1\n'
                    "echo Done. & del \"%~f0\"\n"
                )
                uninst_path = str(bat)
            self._prog(62, "...")
            register_uninstall(d, str(d/EXE_NAME), str(d/ICON_NAME), uninst_path)
            if self.opt_desktop.get():
                self._prog(74, "...")
                desk = Path(os.environ.get("USERPROFILE","~"))/"Desktop"
                create_shortcut(str(d/EXE_NAME), str(desk/f"{APP_NAME}.lnk"), str(d/ICON_NAME), APP_FULL)
            if self.opt_startmenu.get():
                self._prog(86, "...")
                sm = (Path(os.environ["APPDATA"])/"Microsoft"/"Windows"/"Start Menu"/"Programs"/APP_NAME)
                sm.mkdir(parents=True, exist_ok=True)
                create_shortcut(str(d/EXE_NAME), str(sm/f"{APP_NAME}.lnk"), str(d/ICON_NAME), APP_FULL)
            self._prog(100, "OK"); time.sleep(0.4)
            self.after(0, self._done, str(d/EXE_NAME))
        except Exception as e:
            self.after(0, self._error, str(e))

    def _done(self, exe_path):
        for w in self.winfo_children(): w.destroy()
        load_banner(self)
        tk.Frame(self, bg=SUCCESS, height=2).pack(fill="x")
        tk.Frame(self, bg=BG2, height=32).pack(fill="x")
        body = tk.Frame(self, bg=BG, padx=40, pady=28); body.pack(fill="both", expand=True)
        tk.Label(body, text="\u2713", font=("Segoe UI",44), bg=BG, fg=SUCCESS).pack(pady=(0,6))
        tk.Label(body, text=T('inst_sucesso', app=APP_NAME), font=("Segoe UI",13,"bold"),
                 bg=BG, fg=TEXT).pack()
        tk.Label(body, text=APP_FULL, font=("Segoe UI",9), bg=BG, fg=DIM).pack(pady=(4,0))
        footer = tk.Frame(self, bg=BG2, height=54); footer.pack(fill="x", side="bottom")
        footer.pack_propagate(False)
        tk.Label(footer, text=PUBLISHER, font=("Segoe UI",8), bg=BG2, fg=DIM
                 ).place(x=20, rely=0.5, anchor="w")
        if self.opt_launch.get():
            tk.Button(footer, text=T('inst_btn_abrir', app=APP_NAME), bg=ACCENT, fg=WHITE, relief="flat",
                      font=("Segoe UI",10,"bold"), cursor="hand2", padx=22, pady=7,
                      command=lambda: [subprocess.Popen([exe_path]), self.destroy()]
                      ).place(x=540, rely=0.5, anchor="e")
        else:
            tk.Button(footer, text=T('inst_btn_fechar'), bg=ACCENT, fg=WHITE, relief="flat",
                      font=("Segoe UI",10,"bold"), cursor="hand2", padx=22, pady=7,
                      command=self.destroy).place(x=540, rely=0.5, anchor="e")

    def _error(self, msg):
        self.btn_install.config(state="normal", text=T('inst_btn_inst'))
        self.btn_cancel.config(state="normal")
        messagebox.showerror("Error", f"{msg}\n\nTry running as Administrator.")

if __name__ == "__main__":
    # ── EULA aparece ANTES do instalador ─────────────────────────────────
    _eula_aceite = [False]

    def _mostrar_eula_instalador():
        from tkinter import scrolledtext
        _root_eula = tk.Tk()
        _root_eula.configure(bg="#0d1117")
        _root_eula.resizable(True, True)
        sw = _root_eula.winfo_screenwidth(); sh = _root_eula.winfo_screenheight()
        ew = max(860, min(1060, sw - 180))
        eh = max(700, min(860, sh - 120))
        _root_eula.geometry(f"{ew}x{eh}+{(sw-ew)//2}+{max(30,(sh-eh)//2)}")
        _root_eula.minsize(740, 620)
        _root_eula.attributes('-topmost', True)
        _root_eula.after(400, lambda: _root_eula.attributes('-topmost', False))
        _root_eula.protocol('WM_DELETE_WINDOW', lambda: _root_eula.destroy())

        # ── Carregar texto da licença ──────────────────────────────────────
        def _get_lic_text(lang):
            try:
                sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
                from bsp_i18n import licenca_texto
                return licenca_texto(lang=lang, versao=APP_VERSION,
                                     autor="André O. Massuça",
                                     univ="Pedro Aleixo  |  Luís M. Massuça")
            except Exception:
                return (
                    f"BSP - Biomechanical Stability Program  v{APP_VERSION}\n"
                    f"André O. Massuça  |  Pedro Aleixo  |  Luís M. Massuça\n\n"
                    "ACORDO DE LICENÇA DE UTILIZADOR FINAL (EULA)\n"
                    f"© 2025-2026 André O. Massuça, Pedro Aleixo & Luís M. Massuça. Todos os direitos reservados.\n\n"
                    "Leia atentamente antes de instalar. Ao instalar aceita os termos.\n"
                )

        _eula_titles = {
            'PT': 'Acordo de Licença de Utilizador Final (EULA)',
            'EN': 'End User Licence Agreement (EULA)',
            'ES': 'Acuerdo de Licencia de Usuario Final (EULA)',
            'DE': 'Endbenutzer-Lizenzvertrag (EULA)',
        }
        _txt_ref  = [None]
        _lbl_tit  = [None]
        _lang_btns = {}

        def _mudar_lingua(cod):
            definir_lingua(cod)
            # Guardar língua
            try:
                import json as _js
                _cf2 = os.path.join(os.path.expanduser('~'), '.aom_estabilidade_cfg.json')
                try:
                    with open(_cf2, 'r', encoding='utf-8') as _ff: _d2 = _js.load(_ff)
                except Exception: _d2 = {}
                _d2['_lingua'] = cod
                with open(_cf2, 'w', encoding='utf-8') as _ff: _js.dump(_d2, _ff)
            except Exception: pass
            # Actualizar título
            if _lbl_tit[0]:
                _lbl_tit[0].config(text=_eula_titles.get(cod, _eula_titles['PT']))
            # Actualizar texto
            if _txt_ref[0]:
                _txt_ref[0].config(state='normal')
                _txt_ref[0].delete('1.0', 'end')
                _txt_ref[0].insert('end', _get_lic_text(cod))
                _txt_ref[0].config(state='disabled')
            # Actualizar botões
            for c2, b2 in _lang_btns.items():
                _act = (c2 == cod)
                b2.config(bg=CYAN if _act else BG3,
                          fg=BG if _act else DIM,
                          font=("Segoe UI", 8, "bold") if _act else ("Segoe UI", 8))

        # Banner
        load_banner(_root_eula)
        tk.Frame(_root_eula, bg=CYAN, height=2).pack(fill='x')

        # Barra de idioma
        _BANDEIRAS = {'PT': '🇵🇹', 'EN': '🇬🇧', 'ES': '🇪🇸', 'DE': '🇩🇪'}
        _lang_bar = tk.Frame(_root_eula, bg=BG3, height=28)
        _lang_bar.pack(fill='x'); _lang_bar.pack_propagate(False)
        _lang_atual = lingua_atual()
        for _cod, _flag in _BANDEIRAS.items():
            _act = (_cod == _lang_atual)
            _b = tk.Button(_lang_bar, text=f"{_flag} {_cod}",
                           bg=CYAN if _act else BG3,
                           fg=BG if _act else DIM,
                           relief='flat', cursor='hand2',
                           font=("Segoe UI", 8, "bold") if _act else ("Segoe UI", 8),
                           padx=6, pady=2,
                           command=lambda c=_cod: _mudar_lingua(c))
            _b.pack(side='left', fill='y', padx=1)
            _lang_btns[_cod] = _b

        # Sub-header: título + versão
        hdr = tk.Frame(_root_eula, bg=BG2)
        hdr.pack(fill='x')
        _lbl = tk.Label(hdr, text=_eula_titles.get(_lang_atual, _eula_titles['PT']),
                        font=("Segoe UI", 9, "bold"), bg=BG2, fg=CYAN, anchor='w', pady=7)
        _lbl.pack(side='left', padx=14)
        _lbl_tit[0] = _lbl
        tk.Label(hdr, text=f"v{APP_VERSION}", font=("Segoe UI", 8),
                 bg=BG2, fg=DIM, pady=7).pack(side='right', padx=14)

        # Rodapé (empacotado antes do body para garantir espaço)
        footer = tk.Frame(_root_eula, bg=BG2, height=62)
        footer.pack(fill='x', side='bottom'); footer.pack_propagate(False)
        tk.Button(footer, text="✗  Recusar / Decline", bg=BG2, fg="#f85149",
                  relief='flat', font=("Segoe UI", 9), cursor='hand2',
                  padx=14, pady=6,
                  command=lambda: _root_eula.destroy()
                  ).pack(side='left', padx=20)
        tk.Button(footer, text="✓  Li e Aceito os Termos  /  I Accept",
                  bg=CYAN, fg=BG,
                  relief='flat', font=("Segoe UI", 10, "bold"), cursor='hand2',
                  padx=18, pady=8,
                  command=lambda: [_eula_aceite.__setitem__(0, True), _root_eula.destroy()]
                  ).pack(side='right', padx=20)

        # Corpo de texto
        body = tk.Frame(_root_eula, bg=BG, padx=16, pady=8)
        body.pack(fill='both', expand=True)
        txt = scrolledtext.ScrolledText(body, bg=BG2, fg=TEXT,
                                        font=("Segoe UI", 9), wrap='word',
                                        relief='flat', padx=12, pady=10,
                                        highlightthickness=1,
                                        highlightbackground=BG3,
                                        state='normal', cursor='arrow')
        txt.pack(fill='both', expand=True)
        txt.insert('end', _get_lic_text(_lang_atual))
        txt.config(state='disabled')
        _txt_ref[0] = txt

        _root_eula.title(f"BSP v{APP_VERSION}  -  {_eula_titles.get(_lang_atual, _eula_titles['PT'])}")
        _root_eula.mainloop()

    _mostrar_eula_instalador()
    if not _eula_aceite[0]:
        sys.exit(0)

    InstallerApp().mainloop()
